        else:
            if isinstance(data, Sequence):
                data_dict = {}
                for i, var in enumerate(data):
                    key = getattr(var, "name", i)
                    data_dict[key] = pd.Series(var)
                data = data_dict
            if isinstance(data, Mapping):
                data = {key: pd.Series(val) for key, val in data.items()}
